read_file({"path": "internal/language_tiers/tiers.go"}) → // Package language_tiers provides tier classification for programming languages
// based on the depth of analysis support available.
//
// Languages are classified into two tiers:
//   - TierGeneric: baseline support without language-specific structural analysis.
//   - TierNative: full structural analysis support for natively supported languages.
package language_tiers

import "strings"

// Tier represents the level of analysis support for a language.
type Tier int

const (
	// TierGeneric is the baseline tier for languages without specialized analysis.
	TierGeneric Tier = 0
	// TierNative is the tier for languages with full structural analysis support.
	TierNative Tier = 1
)

// TierForLanguage returns the analysis tier for a given language identifier.
// It matches against known natively-supported languages case-insensitively
// (go, typescript, python, rust) and returns TierNative for those;
// all other languages return TierGeneric.
func TierForLanguage(lang string) Tier {
	switch {
	case strings.EqualFold(lang, "go"),
		strings.EqualFold(lang, "typescript"),
		strings.EqualFold(lang, "python"),
		strings.EqualFold(lang, "rust"):
		return TierNative
	default:
		return TierGeneric
	}
}

