	scores := domain.DimensionScores{
		domain.DimCorrectness:                0.8,
		domain.DimMaintainability:            0.8,
		domain.DimReadability:                0.8,
		domain.DimTestability:                0.8,
		domain.DimSecurity:                   0.8,
